      "parameters": {
        "functionCode": "// Compile analytics summary\nconst sessions = $input.item(0).json.total_sessions || 0;\nconst bookings = $input.item(1).json.pending_bookings || 0;\nconst responseTime = Math.round($input.item(2).json.avg_response_time_seconds || 0);\nconst errors = $input.item(3).json.error_count || 0;\n\nconst conversionRate = sessions > 0 ? ((bookings / sessions) * 100).toFixed(1) : '0.0';\nconst status = errors === 0 ? '✅ All systems operational' : `⚠️ ${errors} errors detected`;\n\nlet highlights = '';\nif (bookings >= 5) highlights += '🔥 High booking volume!\\n';\nif (responseTime < 5000) highlights += '⚡ Fast response times!\\n';\nif (errors === 0) highlights += '✅ Zero errors!\\n';\n\nreturn {\n  summary: `📊 Lina Point - Last Hour Summary\\n\\n📱 Active Sessions: ${sessions}\\n📅 Pending Bookings: ${bookings}\\n📈 Conversion Rate: ${conversionRate}%\\n⏱️ Response Time: ${responseTime}ms\\n❌ Errors: ${errors}\\n${highlights}\\n${status}`,\n  metrics: {\n    sessions,\n    bookings,\n    conversionRate,\n    responseTime,\n    errors\n  }\n};"
      },
      "id": "compile-summary",
      "name": "Compile Summary",
      "type": "n8n-nodes-base.function",
      "typeVersion": 1,
      "position": [1450, 100],
      "notes": "Format analytics for admin notification"
