        "functionCode": "// Check for anomalies\nconst conversionRate = $input.first().json.metrics.conversionRate;\nconst errors = $input.first().json.metrics.errors;\nconst responseTime = $input.first().json.metrics.responseTime;\n\nlet anomalies = [];\n\nif (conversionRate < 10) {
  anomalies.push(`📉 Low conversion rate: ${conversionRate}% (target: 20%)`);\n}\nif (errors > 0) {\n  anomalies.push(`⚠️ Errors detected: ${errors} failures`);
}\nif (responseTime > 15000) {\n  anomalies.push(`🐢 Slow response: ${responseTime}ms (target: <5000ms)`);\n}\n\nif (anomalies.length === 0) {\n  return null;\n}\n\nreturn {\n  hasAnomalies: true,\n  message: `🚨 Anomalies Detected:\\n\\n${anomalies.join('\\n')}\\n\\nPlease review logs or contact support.`\n};"
      },
